solutions.javascript:
// Define a generic function mapValues that takes an object and a function as arguments
function mapValues<T>(obj: { [key: string]: T }, fn: (value: T) => T): { [key: string]: T } {
  // Return a new object with the same keys as the input object
  return Object.keys(obj).reduce((acc, key) => {
    // Apply the transformation to each value and specify the type of the output object
    acc[key] = fn(obj[key]) as T;
    return acc;
  }, {} as { [key in keyof typeof obj]: T });
}
